package pb

// manifest_messages.go — message types for the GetDepartureManifest RPC.
//
// Wave-1A manifest API.  These types would normally be generated by protoc;
// they are hand-written here because protoc is unavailable in this environment.

// ManifestJamaah represents one pilgrim row in the departure manifest.
type ManifestJamaah struct {
	BookingID     string `json:"booking_id"`
	Name          string `json:"name"`
	NIK           string `json:"nik"`
	Phone         string `json:"phone"`
	RoomType      string `json:"room_type"`
	BookingStatus string `json:"booking_status"`
	DocStatus     string `json:"doc_status"` // "complete", "partial", "none"
}

// GetDepartureManifestRequest is the input for GetDepartureManifest.
type GetDepartureManifestRequest struct {
	DepartureID string `json:"departure_id"`
}

// GetDepartureManifestResponse is the output for GetDepartureManifest.
type GetDepartureManifestResponse struct {
	DepartureID string            `json:"departure_id"`
	TotalJamaah int32             `json:"total_jamaah"`
	LunasPaid   int32             `json:"lunas_paid"`
	DocComplete int32             `json:"doc_complete"`
	JamaahList  []*ManifestJamaah `json:"jamaah_list"`
}
